def token_hash(token: str) -> str:
    return hashlib.sha256((APP_SECRET + "|" + token).encode("utf-8")).hexdigest()


def rate_limit_check_and_increment(key: str) -> bool:
    db = get_db()
    now = to_ts(utcnow())
    cur = db.execute("SELECT * FROM reset_mfa_rate_limit WHERE key = ?", (key,))
    row = cur.fetchone()
    if not row:
        db.execute(
            "INSERT INTO reset_mfa_rate_limit(key, window_start, count) VALUES(?,?,?)",
            (key, now, 1),
        )
        db.commit()
        return True
    window_start = int(row["window_start"])
    count = int(row["count"])
    if now - window_start >= RESET_RATE_LIMIT_WINDOW_SECONDS:
        db.execute(
            "UPDATE reset_mfa_rate_limit SET window_start = ?, count = ? WHERE key = ?",
            (now, 1, key),
        )
        db.commit()
        return True
    if count >= RESET_RATE_LIMIT_MAX:
        return False
    db.execute(
        "UPDATE reset_mfa_rate_limit SET count = ? WHERE key = ?",
        (count + 1, key),
    )
    db.commit()
    return True


