def totp_now(secret_b32: str, step: int = 30, digits: int = 6) -> str:
    key = base64.b32decode(secret_b32.upper() + "=" * ((8 - (len(secret_b32) % 8)) % 8))
    counter = int(time.time() // step)
    msg = counter.to_bytes(8, "big")
    h = hmac.new(key, msg, hashlib.sha1).digest()
    o = h[-1] & 0x0F
    code_int = (int.from_bytes(h[o:o + 4], "big") & 0x7FFFFFFF) % (10 ** digits)
    return str(code_int).zfill(digits)


def verify_totp(secret_b32: str, code: str, window: int = 1) -> bool:
    code = (code or "").strip()
    if not code.isdigit():
        return False
    key = base64.b32decode(secret_b32.upper() + "=" * ((8 - (len(secret_b32) % 8)) % 8))
    step = 30
    digits = 6
    t = int(time.time() // step)
    for offset in range(-window, window + 1):
        counter = (t + offset).to_bytes(8, "big")
        h = hmac.new(key, counter, hashlib.sha1).digest()
        o = h[-1] & 0x0F
        code_int = (int.from_bytes(h[o:o + 4], "big") & 0x7FFFFFFF) % (10 ** digits)
        if hmac.compare_digest(str(code_int).zfill(digits), code):
            return True
    return False


def new_totp_secret() -> str:
    return base64.b32encode(secrets.token_bytes(20)).decode("ascii").rstrip("=")


