@app.post("/register")
def register():
    data = request.get_json(silent=True) or {}
    email = normalize_email(data.get("email", ""))
    password = data.get("password", "")
    if not is_valid_email(email) or not password or len(password) < 8:
        return jsonify({"error": "invalid_input"}), 400

    db = get_db()
    try:
        db.execute(
            "INSERT INTO users(email, password_hash, mfa_enabled, mfa_secret, created_at) VALUES(?,?,?,?,?)",
            (email, hash_password(password), 0, None, to_ts(utcnow())),
        )
        db.commit()
    except sqlite3.IntegrityError:
        return jsonify({"error": "email_in_use"}), 409

    user = db_user_by_email(email)
    session["user_id"] = int(user["id"])
    return jsonify({"ok": True, "user_id": int(user["id"]), "email": email})


@app.post("/login")
def login():
    data = request.get_json(silent=True) or {}
    email = normalize_email(data.get("email", ""))
    password = data.get("password", "")
    mfa_code = data.get("mfa_code")

    user = db_user_by_email(email)
    if not user:
        return jsonify({"error": "invalid_credentials"}), 401
    if not verify_password(password, user["password_hash"]):
        return jsonify({"error": "invalid_credentials"}), 401

    if int(user["mfa_enabled"]) == 1:
        if not user["mfa_secret"]:
            return jsonify({"error": "mfa_misconfigured"}), 403
        if not mfa_code or not verify_totp(user["mfa_secret"], str(mfa_code)):
            return jsonify({"error": "mfa_required", "mfa": "totp"}), 401

    session["user_id"] = int(user["id"])
    return jsonify({"ok": True, "user_id": int(user["id"])})


@app.post("/logout")
def logout():
    session.clear()
    return jsonify({"ok": True})


