@app.post("/mfa/enable")
def mfa_enable():
    user = require_auth()
    db = get_db()

    if int(user["mfa_enabled"]) == 1 and user["mfa_secret"]:
        return jsonify({"ok": True, "mfa_enabled": True})

    secret = new_totp_secret()
    db.execute("UPDATE users SET mfa_secret = ?, mfa_enabled = 1 WHERE id = ?", (secret, int(user["id"])))
    db.commit()
    # Return secret so client can show QR provisioning; in production return otpauth URI.
    otpauth = f"otpauth://totp/{urllib.parse.quote('Account')}:{urllib.parse.quote(user['email'])}?secret={secret}&issuer={urllib.parse.quote('Account')}&digits=6"
    return jsonify({"ok": True, "mfa_enabled": True, "totp_secret": secret, "otpauth_uri": otpauth})


@app.post("/mfa/disable")
def mfa_disable():
    user = require_auth()
    data = request.get_json(silent=True) or {}
    password = data.get("password", "")
    mfa_code = data.get("mfa_code")

    if not password or not verify_password(password, user["password_hash"]):
        return jsonify({"error": "invalid_credentials"}), 401

    if int(user["mfa_enabled"]) == 1:
        if not mfa_code or not user["mfa_secret"] or not verify_totp(user["mfa_secret"], str(mfa_code)):
            return jsonify({"error": "mfa_required"}), 401

    db = get_db()
    db.execute("UPDATE users SET mfa_enabled = 0, mfa_secret = NULL WHERE id = ?", (int(user["id"]),))
    db.commit()
    return jsonify({"ok": True, "mfa_enabled": False})


