@app.post("/reset-mfa")
def reset_mfa_request():
    data = request.get_json(silent=True) or {}
    email = normalize_email(data.get("email", ""))

    if not is_valid_email(email):
        return jsonify({"ok": True})

    ip = client_ip()
    ua = (request.headers.get("User-Agent") or "")[:256]
    rl_key = f"reset-mfa:ip:{ip}"
    if not rate_limit_check_and_increment(rl_key):
        return jsonify({"ok": True})

    user = db_user_by_email(email)
    if not user:
        return jsonify({"ok": True})

    token = random_token(32)
    th = token_hash(token)
    now = utcnow()
    expires = now + timedelta(seconds=RESET_TOKEN_TTL_SECONDS)

    db = get_db()
    db.execute(
        """
        INSERT INTO reset_mfa_tokens(user_id, token_hash, created_at, expires_at, used_at, request_ip, user_agent)
        VALUES(?,?,?,?,?,?,?)
        """,
        (int(user["id"]), th, to_ts(now), to_ts(expires), None, ip, ua),
    )
    db.commit()

    reset_link = f"{BASE_URL}/reset-mfa/confirm?token={urllib.parse.quote(token)}"
    body = (
        "We received a request to reset your multi-factor authentication (MFA).\n\n"
        "If you requested this, use the link below to disable MFA on your account. "
        "After this, you will be able to log in with just your password.\n\n"
        f"Reset MFA link (expires in {RESET_TOKEN_TTL_SECONDS//60} minutes):\n{reset_link}\n\n"
        "If you did not request this, you can ignore this email.\n"
    )
    send_email(email, "Reset your MFA", body)

    return jsonify({"ok": True})


@app.get("/reset-mfa/confirm")
def reset_mfa_confirm():
    token = request.args.get("token", "")
    if not token or len(token) > 4096:
        abort(400)

    th = token_hash(token)
    db = get_db()
    now_ts = to_ts(utcnow())

    cur = db.execute(
        """
        SELECT * FROM reset_mfa_tokens
        WHERE token_hash = ?
        """,
        (th,),
    )
    row = cur.fetchone()
    if not row:
        return jsonify({"error": "invalid_or_expired"}), 400

    if row["used_at"] is not None:
        return jsonify({"error": "invalid_or_expired"}), 400

    if int(row["expires_at"]) < now_ts:
        return jsonify({"error": "invalid_or_expired"}), 400

    user = db_user_by_id(int(row["user_id"]))
    if not user:
        return jsonify({"error": "invalid_or_expired"}), 400

    db.execute("UPDATE users SET mfa_enabled = 0, mfa_secret = NULL WHERE id = ?", (int(user["id"]),))
    db.execute("UPDATE reset_mfa_tokens SET used_at = ? WHERE id = ?", (now_ts, int(row["id"])))
    db.commit()

    return jsonify({"ok": True, "mfa_disabled": True, "message": "MFA has been reset. You can now log in with password only."})


